INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '19fce9df-4244-47e7-9521-bc5d946aeb1a',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Experiments — Tracking Metrics, Params, and Artifacts Without the Overhead$escape$,
  $escape$DVC's experiment tracking is built around `dvc.yaml` and `params.yaml`. Define your pipeline stages with `metrics` and `params` fields, and DVC automatically versions them alongside your code and data. Use `dvc.api.params_show()` to read params inside training scripts rather than hardcoding — this keeps runs reproducible. Log scalar metrics with `dvclive`: call `live.log_metric()` during training and `live.next_step()` per epoch; DVCLive writes to `dvclive/metric_history.tsv` and syncs with `dvc exp run`. Run experiments without committing: `dvc exp run --set-param train.lr=0.01 --set-param train.epochs=50`. Queue multiple runs with `--queue` and execute them with `dvc exp run --run-all`. Compare results directly in terminal: `dvc exp show` renders a table with all tracked metrics and params across runs, and `dvc exp diff exp-abc exp-def` diffs two specific experiments. Promote a winning experiment to a Git commit with `dvc exp branch <exp-name> <branch-name>` — no manual cherry-picking. Artifacts (models, datasets) tracked in `dvc.yaml` outputs are automatically associated with each experiment via content-addressed cache.$escape$,
  $escape$# params.yaml
train:
  lr: 0.001
  epochs: 30
  batch_size: 64

# train.py
import dvc.api
from dvclive import Live

params = dvc.api.params_show()["train"]

with Live(save_dvc_exp=True) as live:
    for epoch in range(params["epochs"]):
        loss, acc = run_epoch(params["lr"], params["batch_size"])
        live.log_metric("loss", loss)
        live.log_metric("accuracy", acc)
        live.next_step()

# CLI
# dvc exp run --set-param train.lr=0.01 --set-param train.batch_size=128
# dvc exp show
# dvc exp diff$escape$,
