INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'beb1cb2f-4a67-4dff-a3b3-29a36e763194',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC + MLflow — Bridging Pipeline Reproducibility with Experiment Tracking$escape$,
  $escape$DVC handles data versioning and pipeline reproducibility; MLflow handles experiment tracking and model registry. DVCLive bridges them natively. When you run a DVC stage, DVCLive can mirror all `log_metric`, `log_param`, and `log_artifact` calls to an MLflow tracking server by setting `MLFLOW_TRACKING_URI` and enabling the MLflow logger in your `Live()` context. Each `dvc exp run` becomes an MLflow run — params from `dvc.yaml` params block map to MLflow params, and `live.log_metric()` calls populate MLflow's metric history. For model registry, after training completes inside a DVC stage, use `mlflow.register_model()` pointing at the artifact logged during the run. This means `dvc repro` drives reproducibility (locked deps, cached outputs, git-tracked params) while MLflow gives your team a central UI for comparing runs across branches. Crucially, DVC experiment commits (`--save-dvc-exp`) and MLflow run IDs stay correlated — you can trace any MLflow run back to an exact git ref and DVC cache state.$escape$,
  $escape$# dvc.yaml stage — DVCLive mirrors to MLflow automatically
stages:
  train:
    cmd: python train.py
    deps: [data/train.csv]
    params: [params.yaml]
    metrics: [dvclive/metrics.json]
    outs: [models/]

# train.py
import os
from dvclive import Live
import mlflow

os.environ["MLFLOW_TRACKING_URI"] = "http://localhost:5000"

with Live(save_dvc_exp=True) as live:
    live.log_param("learning_rate", 0.001)
    for epoch in range(epochs):
        live.log_metric("loss", compute_loss())
        live.next_step()
    mlflow.register_model(f"runs:/{live.run.info.run_id}/model", "MyModel")$escape$,
  $escape$python$escape$,
