INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '48a216b1-690f-40a1-a45f-bc1087aa293f',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC + Weights & Biases — Experiment Tracking, Sweeps, and Reports in One Pipeline$escape$,
  $escape$DVCLive bridges DVC's reproducibility model with W&B's visualization layer. Pass `report="wandb"` to `Live()` and every `live.log_metric()` call syncs to your W&B run automatically — no manual `wandb.log()` needed. DVC still owns your data versioning and pipeline DAG; W&B owns the dashboards.

For hyperparameter sweeps, define a `sweep.yaml` with W&B's Bayes or grid method, then point `program` at a shell script that calls `dvc exp run --set-param train.lr=${lr}`. The sweep agent spawns workers, each invoking a fully reproducible DVC pipeline stage. Every run is git-committed as a `dvc exp` branch — you get W&B's sweep charts *and* DVC's experiment branching.

Reports pull from W&B run history across your sweep, letting you correlate `params.yaml` values against tracked metrics. Since DVCLive auto-tags runs with the DVC commit hash, you can trace any W&B report data point back to an exact `dvc exp show` row. Use `dvc exp push origin` to share the winning run's cached artifacts alongside the W&B report URL.$escape$,
  $escape$# train.py — DVCLive auto-syncs to W&B
from dvclive import Live
import yaml

with open("params.yaml") as f:
    params = yaml.safe_load(f)["train"]

with Live(report="wandb") as live:
    live.log_params(params)

    for epoch in range(params["epochs"]):
        loss, acc = train_one_epoch(params["lr"])
        live.log_metric("loss", loss)
        live.log_metric("accuracy", acc)
        live.next_step()  # commits step to W&B + dvclive/metric_history.tsv$escape$,
  $escape$python$escape$,
