INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9dea47a5-f15a-43ac-b129-a7eb7f715172',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC foreach Stages — Parameterize Pipelines Without Copy-Paste$escape$,
  $escape$DVC's `foreach` stage definition lets you declare a single stage template and instantiate it across multiple values — no shell loops, no duplicate stage blocks. Reference `${item}` inside the `do` block and DVC expands it into distinct named stages (`train@small`, `train@medium`, `train@large`), each tracked independently in the run-cache.

This integrates directly with remote storage. Every stage's outputs are content-addressed by input hashes. After `dvc push`, teammates run `dvc pull` to fetch only the artifacts they need. On `dvc repro`, DVC compares input checksums against the run-cache and skips any stage whose inputs haven't changed — changing `data/large` only re-runs `train@large`.

Params stay decoupled from stage logic via `params.yaml`. Modify `model.lr` and only the foreach variants dependent on that param re-execute. This makes hyperparameter sweeps first-class pipeline citizens. Configure your remote once in `.dvc/config` with `dvc remote add -d myremote s3://bucket/cache` — all content-addressed artifacts share the same backend across the whole team without data duplication.$escape$,
  $escape$# dvc.yaml
stages:
  train:
    foreach:
      - small
      - medium
      - large
    do:
      cmd: python train.py --size ${item}
      deps:
        - data/${item}
        - train.py
      params:
        - params.yaml:
            - model.lr
            - model.epochs
      outs:
        - models/${item}/model.pkl

# Run only stages with changed inputs
# dvc repro --glob 'train@*'$escape$,
  $escape$bash$escape$,
