INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2978737b-02f6-4415-a223-b285883f0ccb',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Model Registry — Versioning, Staging, and Promotion Workflows$escape$,
  $escape$DVC's Model Registry lives inside your Git repo under `dvclive` or a dedicated `models/` directory registered via `dvc.yaml`. You register a model artifact using `dvc params` tracking or the GTO (Git Tag Operations) library that ships with DVC Studio. Each model version is a Git tag following the pattern `<model-name>#v<semver>` — e.g., `fraud-detector#v1.2.0`. Stages map directly to tag suffixes: `fraud-detector#v1.2.0#staging` promotes the artifact to staging, while `fraud-detector#v1.2.0#production` marks it live.

Promotion is done via `gto assign <model> --version v1.2.0 --stage production`, which pushes a Git tag. CI/CD pipelines watch for these tags using `gto check-ref` to gate deployments — no tag, no deploy. Approval workflows are enforced through standard Git branch protection: require PR review before tagging to production. `gto history <model>` gives a full audit trail of every stage transition, tied to the exact commit hash of the training run that produced the artifact.$escape$,
  $escape$# Register a new model version
gto register fraud-detector --rev HEAD

# Promote to staging
gto assign fraud-detector --version v1.2.0 --stage staging

# Promote to production (after review)
gto assign fraud-detector --version v1.2.0 --stage production

# In CI: check if the pushed tag is a production assignment
gto check-ref $GITHUB_REF --stage production && echo "Deploy to prod"

# Full audit trail
gto history fraud-detector$escape$,
  $escape$bash$escape$,
