INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '428cdbf7-4203-4fcf-bf93-683742312673',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC — Versioning ONNX Model Exports as Reproducible Pipeline Stages$escape$,
  $escape$ONNX gives you a portable, runtime-agnostic model format, but without DVC, your export step is an undocumented shell command someone ran once. Wire the export directly into `dvc.yaml` as a pipeline stage, declaring your trained weights as `deps` and the `.onnx` file as an `out`. DVC hashes both, so `dvc repro` re-runs the export only when the upstream checkpoint changes. Store export hyperparameters (opset version, dynamic axes config) in `params.yaml` and reference them via `params:` — now they're tracked in `dvc.lock` alongside the artifact. Push the `.onnx` to your remote with `dvc push`, and any teammate or CI job can `dvc pull` the exact artifact tied to that Git commit without re-running training. For ONNX Runtime inference, pull the versioned artifact into your serving container the same way. This makes model format conversion a first-class, auditable step in your lineage graph rather than a one-off script, and lets you compare exported models across experiments using `dvc params diff` and `dvc metrics diff`.$escape$,
  $escape$# dvc.yaml
stages:
  export_onnx:
    cmd: python src/export_onnx.py
    deps:
      - src/export_onnx.py
      - models/checkpoint.pt
    params:
      - params.yaml:
        - onnx.opset_version
        - onnx.dynamic_axes
    outs:
      - models/model.onnx

# params.yaml
onnx:
  opset_version: 17
  dynamic_axes: {input: [0], output: [0]}

# Reproduce only if deps/params changed
# dvc repro export_onnx
# dvc push models/model.onnx$escape$,
  $escape$bash$escape$,
