INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '25f3ec19-0995-49fe-8a87-7e443d600f2e',
  '00000000-0000-0000-0000-000000000001',
  $escape$dvc + TensorRT — Version Engines, Track Quantization Tradeoffs, Never Rebuild Blindly$escape$,
  $escape$TensorRT `.engine` files are binary, GPU-architecture-specific, and expensive to rebuild — making them ideal DVC artifacts. Define your engine build as a `dvc.yaml` stage with `params.yaml` controlling precision (`fp32`/`fp16`/`int8`), `max_workspace_gb`, and `batch_size`. DVC hashes the ONNX source and params together, so the engine only rebuilds when inputs actually change.

Capture latency (p99 ms) and accuracy (mAP or top-1) into `metrics.json` from your TRT benchmark script. Run `dvc exp run --set-param precision=int8` to sweep quantization levels without touching code. `dvc metrics diff` then surfaces the latency/accuracy tradeoff across experiments side-by-side.

INT8 calibration datasets must be a `deps` entry — DVC invalidates the engine cache automatically when the calibration data changes. Push multi-GB `.engine` files to S3/GCS remote storage; teammates run `dvc pull` to get pre-built engines instead of a 20-minute local rebuild.

`dvc exp show --sort-by metrics.json:latency_p99` immediately surfaces your Pareto-optimal precision config across all recorded runs.$escape$,
  $escape$# dvc.yaml
stages:
  build_engine:
    cmd: python build_engine.py
    deps:
      - model.onnx
      - calibration_data/
      - build_engine.py
    params:
      - precision
      - max_workspace_gb
      - batch_size
    outs:
      - model.engine
  benchmark:
    cmd: python benchmark.py --engine model.engine --out metrics.json
    deps:
      - model.engine
    metrics:
      - metrics.json:
          cache: false

# params.yaml
precision: fp16
max_workspace_gb: 4
batch_size: 8

# Sweep quantization — compare latency vs accuracy
# dvc exp run --set-param precision=int8
# dvc exp run --set-param precision=fp32
# dvc exp show --sort-by metrics.json:latency_p99$escape$,
  $escape$bash$escape$,
