INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '503bbbdf-dd34-4756-b012-c038bf28274c',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC + Ray — Versioned HPO Pipelines and Artifact-Gated Serving$escape$,
  $escape$DVC pipelines wrap Ray Tune HPO runs cleanly: define a `dvc.yaml` stage whose `cmd` calls your Ray script, declare `params.yaml` keys under `params:`, and point `metrics:` at DVCLive's output directory. When you run `dvc exp run`, DVC feeds your versioned dataset to Ray's distributed workers and captures every trial's metrics through `dvclive`.

Inside each trial, instantiate `Live()` and call `live.log_metric()` + `live.next_step()` per epoch. DVCLive writes per-step metric files that DVC's experiment tracker surfaces in `dvc exp show`. After `Tuner.fit()` completes, the best checkpoint becomes a tracked `outs:` artifact in your stage — `dvc push` syncs it to remote storage.

For Ray Serve, add a downstream `dvc.yaml` stage that lists that model artifact under `deps:`. Your serving script calls `dvc pull` to hydrate the checkpoint before invoking `serve.run()`. The DAG ensures the serve stage only re-executes when the upstream model's content hash changes — no stale deployments, full lineage from raw data to live endpoint.$escape$,
  $escape$# train_ray.py — invoked by dvc repro via dvc.yaml
import yaml
from ray import tune
from dvclive import Live

with open("params.yaml") as f:
    cfg = yaml.safe_load(f)["ray"]

def trial(config):
    with Live() as live:
        loss = train_model(config["lr"], config["depth"])
        live.log_metric("val_loss", loss)
    tune.report({"val_loss": loss})

tuner = tune.Tuner(
    trial,
    param_space={"lr": tune.loguniform(1e-4, 0.1), "depth": tune.randint(2, 8)},
    tune_config=tune.TuneConfig(num_samples=cfg["num_samples"]),
)
tuner.fit()$escape$,
  $escape$python$escape$,
