INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad23c2aa-912d-4369-ac84-2ebe3a6198b7',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Hyperparameter Search — Grid, Random, and Bayesian with dvc exp$escape$,
  $escape$DVC's experiment engine treats each hyperparameter run as a versioned, reproducible unit. Grid search is the bluntest tool: queue every combination with `dvc exp run --queue --set-param 'train.lr=0.001,0.01,0.1' --set-param 'train.batch_size=32,64'`, then `dvc queue start --jobs 4` for parallel execution. Every result is tracked in `.dvc/tmp/exps` and comparable via `dvc exp show`.

Random search cuts cost by sampling a budget of trials instead of exhausting the grid — same CLI, just fewer `--set-param` values chosen stochastically in your orchestration script.

For Bayesian search, pair DVC with Optuna and DVCLive. Each `trial` callback logs params and metrics via `live.log_param` / `live.log_metric`, and Optuna's TPE sampler uses those results to propose better candidates. DVCLive's `step` API doubles as your early-stopping hook: emit `live.log_metric('val_loss', val)` each epoch and check `trial.should_prune()` — Optuna's MedianPruner halts unpromising runs before they waste compute. Compare all survivors with `dvc exp show --sort-by metrics.val_loss --num 10`.$escape$,
  $escape$import optuna
from dvclive import Live

def objective(trial):
    lr = trial.suggest_float("lr", 1e-4, 1e-1, log=True)
    depth = trial.suggest_int("depth", 3, 8)

    with Live(dir="dvclive", save_dvc_exp=True) as live:
        live.log_param("lr", lr)
        live.log_param("depth", depth)

        for epoch, val_loss in train(lr=lr, depth=depth):
            live.log_metric("val_loss", val_loss)
            live.next_step()
            if trial.should_prune():
                raise optuna.TrialPruned()

    return val_loss

study = optuna.create_study(pruner=optuna.pruners.MedianPruner())
study.optimize(objective, n_trials=40)$escape$,
  $escape$python$escape$,
