INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6f9b66b2-6e8b-4ec2-92df-3567baae1bab',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC + FastAPI — Serving Version-Pinned Models via dvc.api$escape$,
  $escape$DVC's Python API lets you pull versioned model artifacts directly into a serving process without a separate model store. `dvc.api.open()` accepts a `rev` parameter — a Git tag, branch, or commit — so your inference server declares exactly which artifact it consumes. Pair this with `dvc.api.params_show()` to read `params.yaml` keys like `serve.batch_size` and `serve.latency_sla_ms` from the same config file used during training. This keeps serving behavior coupled to the experiment that produced the model, eliminating config drift.

For latency SLAs, enforce the budget at the route level: record wall-clock time around `model.predict()` and return a 503 with a `X-Latency-Budget-Exceeded` header when you breach the threshold. The batch size cap from `params.yaml` bounds worst-case inference time deterministically. When you promote a new model version via `dvc push` and retag the artifact, the server restarts against the new `rev` with zero config changes — the params file travels with the artifact in the DVC cache.$escape$,
  $escape$import dvc.api, joblib, time
from fastapi import FastAPI, Response
from pydantic import BaseModel

app = FastAPI()
params = dvc.api.params_show()["serve"]

with dvc.api.open("models/classifier.pkl", rev=params["model_rev"]) as f:
    model = joblib.load(f)

class Batch(BaseModel):
    features: list[list[float]]

@app.post("/predict")
def predict(batch: Batch, response: Response):
    rows = batch.features[: params["batch_size"]]
    t0 = time.perf_counter()
    preds = model.predict(rows).tolist()
    elapsed_ms = (time.perf_counter() - t0) * 1000
    if elapsed_ms > params["latency_sla_ms"]:
        response.headers["X-Latency-Budget-Exceeded"] = f"{elapsed_ms:.1f}ms"
        response.status_code = 503
    return {"predictions": preds, "latency_ms": round(elapsed_ms, 2)}$escape$,
  $escape$python$escape$,
