INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fd7e75de-ee95-49f9-b128-00a79b0d340b',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Model Monitoring — Catching Prediction Drift and Performance Degradation in Prod$escape$,
  $escape$DVC's production monitoring story is built on DVCLive. Wrap each inference batch in a `Live` context to log prediction distributions and ground-truth labels as they arrive. Compute KS-statistic between your reference distribution (snapshotted at training time with `np.save`) and live predictions using `scipy.stats.ks_2samp`, then push that value with `live.log_metric('ks_stat', ks_stat)`. DVCLive persists metrics to `dvc.yaml`-compatible JSON, so `dvc metrics diff baseline HEAD` gives a clean drift delta across any two Git refs — no separate dashboard required.

For data drift, log per-feature statistics (mean, std, null rate) as metrics each batch. Wire monitoring as a downstream DVC pipeline stage: if `ks_stat > 0.1`, the stage exits non-zero, blocking automated retraining triggers. Use `live.log_sklearn_plot('calibration_curve', y_true, y_prob)` to surface probability degradation before raw accuracy drops. Run `dvc plots diff prod-week-1 prod-week-4` to overlay calibration curves across rolling windows — a leading indicator of silent model rot before SLA breaches surface in dashboards.$escape$,
  $escape$import numpy as np
from dvclive import Live
from scipy.stats import ks_2samp
from sklearn.metrics import accuracy_score

ref_preds = np.load("artifacts/ref_predictions.npy")
prod_preds = model.predict(X_batch)

ks_stat, p_value = ks_2samp(ref_preds, prod_preds)

with Live("monitoring", report="html") as live:
    live.log_metric("ks_stat", float(ks_stat))
    live.log_metric("drift_p_value", float(p_value))
    live.log_metric("accuracy", accuracy_score(y_batch, prod_preds))
    live.log_sklearn_plot("calibration_curve", y_batch, prod_preds)

if ks_stat > 0.1:
    raise SystemExit(1)  # Fails DVC stage, blocks retraining pipeline$escape$,
  $escape$python$escape$,
