INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '46442f4c-9ce2-444d-b2b3-eb736391ae69',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC — Versioning int8/fp16 Quantization Trade-offs as Reproducible Experiments$escape$,
  $escape$When you quantize from fp32 to int8, you're trading accuracy for size and latency. DVC makes that trade-off auditable. Define a `quantize` stage in `dvc.yaml` with your full-precision checkpoint as a dep and the quantized artifact as an out — DVC tracks the binary under content-addressed storage. Push quantization hyperparameters (dtype, calibration samples, per-channel vs per-tensor) into `params.yaml` so `dvc repro` detects config drift automatically. Log accuracy, model size in MB, and latency into a JSON metrics file; `dvc metrics diff` then shows exactly what you gave up versus the fp32 baseline. For pruning, track sparsity ratio as a param and remaining parameter count as a metric. Use `dvc exp run --set-param quant.dtype=int8` and `--set-param quant.dtype=fp16` to branch experiments without creating Git branches. `dvc exp show` renders a table comparing all variants side-by-side. The real payoff: every size/accuracy trade-off is a reproducible, diffable, shareable experiment — not a Slack message saying 'I think int8 was good enough.'$escape$,
  $escape$# Run int8 and fp16 quantization as tracked DVC experiments
dvc exp run --set-param quant.dtype=int8 --set-param quant.calib_samples=512
dvc exp run --set-param quant.dtype=fp16 --set-param quant.calib_samples=512

# Compare accuracy vs size across all runs
dvc exp show --select quant.dtype,metrics.accuracy,metrics.model_size_mb

# Diff quantized metrics against fp32 baseline on current branch
dvc metrics diff main

# Promote the winning experiment and push quantized artifact to remote
dvc exp apply exp-3a7f92c
dvc push$escape$,
  $escape$bash$escape$,
