INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1621c563-5605-4a17-b701-05f61f419b60',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Pipelines — Feature Engineering, Validation, and Drift Detection in One DAG$escape$,
  $escape$DVC pipelines let you encode your entire ML data workflow as a reproducible DAG in `dvc.yaml`. Each stage declares `deps`, `outs`, and `cmd`, so DVC tracks exactly what changed and reruns only stale stages. For feature engineering, define a `featurize` stage that reads raw data and writes transformed parquet to `data/features/`. Chain a `validate` stage that runs Great Expectations or Pandera checks against those features — if validation fails, the pipeline halts before training. For drift detection, add a `drift` stage that compares the current feature distribution against a stored baseline using `evidently` or a custom script, writing a `drift_report.json` as an out. DVC's content-addressed cache means re-running `dvc repro` on unchanged data is instant — it restores outputs from cache rather than recomputing. Use `dvc params.yaml` to version distribution thresholds, so changing a drift tolerance triggers only the `drift` stage, not the entire pipeline. Combine with `dvc metrics show` to surface validation pass rates and drift scores across experiments.$escape$,
  $escape$stages:
  featurize:
    cmd: python src/featurize.py
    deps: [data/raw/train.csv, src/featurize.py]
    outs: [data/features/train.parquet]

  validate:
    cmd: python src/validate.py
    deps: [data/features/train.parquet, src/validate.py]
    outs: [reports/validation.json]
    metrics: [reports/validation.json]

  drift:
    cmd: python src/drift.py --threshold ${drift.threshold}
    deps: [data/features/train.parquet, data/baseline/ref.parquet]
    params: [drift.threshold]
    metrics: [reports/drift_report.json]$escape$,
  $escape$bash$escape$,
