INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0d591ed-0e38-4357-993e-279ddaf5c784',
  '00000000-0000-0000-0000-000000000001',
  $escape$DVC Checkpoints — Surviving Spot Instance Preemptions Without Losing Training Progress$escape$,
  $escape$Spot instances can vanish mid-epoch. Without checkpointing, you lose hours of GPU time and pay again to restart. DVC's checkpoint outputs solve this at the pipeline level — not the application level.

Mark a stage output as `checkpoint: true` in `dvc.yaml`. DVC then commits that output to the DVC cache after every `Live.next_step()` call via DVCLive. If your spot instance is preempted, re-running `dvc exp run` on a fresh instance resumes from the last committed checkpoint rather than epoch zero — the cache is already warm on your remote (S3, GCS, Azure Blob).

Pair this with `dvc exp run --queue` to enqueue a sweep of hyperparameter configs before your spot fleet even launches. `dvc queue start --jobs 4` distributes them across workers. Preempted workers drop their queue item back; surviving workers pick it up. Each completed epoch is a cache hit — never recomputed.

Use `dvc exp show` to inspect which checkpoint epoch each queued experiment reached, so you prioritize restarting the runs closest to convergence rather than blindly re-queuing everything.$escape$,
  $escape$# dvc.yaml
stages:
  train:
    cmd: python train.py
    deps:
      - data/
      - train.py
    outs:
      - checkpoints/:
          checkpoint: true

# train.py
from dvclive import Live
import torch

with Live() as live:
    model = load_or_init("checkpoints/")
    for epoch in range(params["epochs"]):
        loss = train_one_epoch(model)
        live.log_metric("loss", loss)
        torch.save(model.state_dict(), "checkpoints/model.pt")
        live.next_step()  # triggers DVC checkpoint commit$escape$,
  $escape$python$escape$,
